text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "topic": "릴리즈 목표일",
        "decision": "스모크 테스트 통과 시 공개 릴리즈 목표를 `금요일 15:00 KST`로 확정."
      },
      {
        "topic": "smoke-theme-pack.mjs 동작 정책",
        "decision": "packageName 불일치가 발생하더라도 스크립트를 무조건 무시하지 않는다. 먼저 패키지 설정을 먼저 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토 대상으로 넘긴다."
      },
      {
        "topic": "액션 아이템 1",
        "decision": "Minjun이 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다."
      },
      {
        "topic": "액션 아이템 2",
        "decision": "Doyun이 금요일 12:00 KST까지 실패 트리아지 노트를 `action_items.md`에 작성한다."
      },
      {
        "topic": "릴리즈 전 체크 포인트",
        "decision": "Hara가 Minjun의 스모크 결과 게시 후 생성된 tarball 경로를 확인한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경",
        "result": "회의에서 논의 후 기각."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개 이전 릴리즈 진행",
        "status": "내부 stretch goal로만 언급됨. 최종 목표로 확정되지 않음."
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 릴리즈가 지연될 수 있음."
      },
      {
        "risk": "README 설치 가이드가 오래된 내용이면 릴리즈 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리즈 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리즈 노트에 내부 수요일 stretch goal을 언급할지 여부."
      },
      {
        "question": "README 점검은 누가 최종 책임지고 완료할지(현재 미배정)."
      }
    ],
    "non_decisions": [
      {
        "item": "고객/외부 파트너, 예산, 보안 사고, 운영 장애, 법무 승인, 오너/책임자(특정 항목), 일부 데드라인(특히 Hara)은 회의록에서 명시되지 않음."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트 작성 (`action_items.md`)",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 tarball 경로 검증",
      "due": "결과 게시 후(정해진 마감일 없음)",
      "status": "확정",
      "source_certainty": "중간"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 검토",
      "due": "목요일 가능 시(정해진 마감일 없음)",
      "status": "미확정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전 Minjun의 스모크 재실행 결과 도착 여부 확인",
      "스모크 통과 시 금요일 15:00 KST 공개 릴리즈 목표 재확인",
      "실패 시 `action_items.md`의 트리아지 노트 반영 상태 및 원인 분류 완료 여부 확인",
      "tarball 경로 검증 결과 반영",
      "README 최신성 점검 후 안내문/릴리즈 노트 반영 여부 확인",
      "오픈 질문(최종 승인 권한자, 릴리즈 노트 문구) 답변 수렴"
    ],
    "what_not_to_invent": [
      "고객 이름 또는 외부 파트너 존재",
      "예산 수치/범위",
      "보안 이슈, 장애 발생, 법무 승인 필요성",
      "추가 오너/책임자 또는 미확정 마감일의 임의 지정",
      "회의에서 논의되지 않은 기술 결정"
    ]
  },
  "non_invention_rules": [
    "확인되지 않은 항목은 '미지정/미확정'으로만 표기하고 새 사실로 채우지 않는다.",
    "고객, 예산, 보안, 장애, 법무, 오너, 마감일은 회의록에 명시된 범위만 사용한다.",
    "open questions는 열린 질문으로 유지하고 결론을 임의로 추가하지 않는다.",
    "회사가 추정한 합의(예: 수요일 릴리즈)는 내부 stretch goal로만 처리하고 공개 목표로 확정하지 않는다."
  ]
}
